package schema

import (
	"entgo.io/ent"
	"entgo.io/ent/dialect"
	"entgo.io/ent/dialect/entsql"
	"entgo.io/ent/schema/edge"
	"entgo.io/ent/schema/field"
	"entgo.io/ent/schema/index"
	"github.com/alpacahq/alpacadecimal"

	"github.com/openmeterio/openmeter/pkg/framework/entutils"
)

type Widget struct{ ent.Schema }

func (Widget) Mixin() []ent.Mixin {
	return []ent.Mixin{entutils.IDMixin{}, entutils.NamespaceMixin{}, entutils.AnnotationsMixin{}, entutils.TimeMixin{}}
}

func (Widget) Fields() []ent.Field {
	return []ent.Field{
		field.String("owner_id").Immutable().SchemaType(map[string]string{dialect.Postgres: "char(26)"}),
		field.Other("amount", alpacadecimal.Decimal{}).SchemaType(map[string]string{dialect.Postgres: "numeric"}),
		field.String("key").NotEmpty(),
	}
}

func (Widget) Indexes() []ent.Index {
	return []ent.Index{index.Fields("namespace", "key").Annotations(entsql.IndexWhere("deleted_at IS NULL")).Unique()}
}

func (Widget) Edges() []ent.Edge {
	return []ent.Edge{edge.From("owner", Customer.Type).Ref("widgets").Field("owner_id").Required().Immutable().Unique()}
}

import (
	enttx "github.com/openmeterio/openmeter/openmeter/ent/tx"
	"github.com/openmeterio/openmeter/openmeter/ent/db"
	"github.com/openmeterio/openmeter/pkg/framework/transaction"
)

var creator transaction.Creator = enttx.NewCreator(entClient) // entClient *db.Client
